text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "내용": "공개 릴리스 목표 시각은 스모크 테스트 통과를 전제로 금요일 15:00 KST로 확정",
        "조건": "스모크 테스트 통과 시"
      },
      {
        "내용": "packageName 불일치 발생 시 우선 패키지 설정(컨피그)을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표로만 유지",
        "확정여부": "비확정(공개 릴리스 결정 아님)"
      }
    ],
    "non_decisions": [
      {
        "내용": "README 설치 단계는 가능하면 목요일까지 검토 필요 의견이 있었으나 담당자 미지정"
      },
      {
        "내용": "Hara의 tarball 경로 점검은 수행 합의는 있으나 정확한 완료 시각 미설정"
      }
    ],
    "risks": [
      {
        "내용": "잘못된 tarball 경로로 릴리스 지연 가능"
      },
      {
        "내용": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해 유발 가능"
      }
    ],
    "open_questions": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "담당자 미지정",
      "source_certainty": "proposed_unassigned"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "예정",
      "source_certainty": "confirmed_no_exact_deadline"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 기준 Minjun 스모크 테스트 결과 수신 여부 확인",
      "금요일 12:00 KST 기준 Doyun의 action_items.md 트리아지 노트 반영 여부 확인",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과 확인",
      "README 설치 단계 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자/소유자",
      "명시되지 않은 마감시각"
    ]
  },
  "non_invention_rules": [
    "명시된 회의 원문에 없는 사실은 추가하지 않는다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실은 '언급 없음' 범위를 넘겨 추정하지 않는다.",
    "담당자 미지정 항목은 owner를 null로 유지한다.",
    "정확한 시각이 없는 항목은 due를 '미정' 또는 조건부 표현으로 유지한다.",
    "확정 결정, 거절 제안, 내부 스트레치 목표, 리스크, 오픈 질문을 반드시 분리 기록한다."
  ]
}
